static Type getSupertype(Type context, Class<?> contextRawType, Class<?> supertype) {
    // wildcards are useless for resolving supertypes. As the upper bound has the same raw type, use it instead
    checkArgument(supertype.isAssignableFrom(contextRawType));
    Type resolved = resolve(context, contextRawType,
        $Gson$Types.getGenericSupertype(context, contextRawType, supertype));

    // Handle wildcard types by returning their upper bounds
    if (resolved instanceof WildcardType) {
        WildcardType wildcard = (WildcardType) resolved;
        Type[] upperBounds = wildcard.getUpperBounds();
        if (upperBounds.length > 0) {
            // Use the first upper bound (typically there's only one)
            return upperBounds[0];
        }
    }

    return resolved;
}

