    if (str.startsWith("_")) {
        if (str.length() < 2) {
            throw new IllegalArgumentException("Invalid locale format: " + str);
        }
        final char ch1 = str.charAt(1);
        if (ch1 == '_') {
            // Case: __Variant
            if (str.length() < 3) {
                throw new IllegalArgumentException("Invalid locale format: " + str);
            }
            return new Locale("", "", str.substring(2));
        } else {
            // Case: _Country or _Country_Variant
            final int nextUnderscore = str.indexOf('_', 1);
            if (nextUnderscore == -1) {
                if (str.length() == 3 && Character.isUpperCase(ch1) && Character.isUpperCase(str.charAt(2))) {
                    return new Locale("", str.substring(1, 3));
                } else {
                    throw new IllegalArgumentException("Invalid locale format: " + str);
                }
            } else {
                final String country = str.substring(1, nextUnderscore);
                if (country.length() != 2 || !Character.isUpperCase(country.charAt(0)) || !Character.isUpperCase(country.charAt(1))) {
