private boolean isNamespacePlaceholder(Node node) {
  if (node.getType() != Token.VAR) {
    return false;
  }
  Node nameNode = node.getFirstChild();
  return nameNode != null && 
         nameNode.getType() == Token.NAME && 
         nameNode.getFirstChild() != null &&
         nameNode.getFirstChild().getType() == Token.OBJECTLIT &&
         nameNode.getFirstChild().getFirstChild() == null;
}

