        throw new IllegalArgumentException("Invalid locale format: " + str);
    }
    if (str.startsWith("_")) {
        throw new IllegalArgumentException("Invalid locale format: " + str);
    }

    String[] parts = str.split("_", -1);
    int len = parts.length;

    if (len > 3) {
        throw new IllegalArgumentException("Invalid locale format: " + str);
    }

    // Language is mandatory
    String language = parts[0];
    if (language.isEmpty() || !isAllLowerCaseAlpha(language)) {
        throw new IllegalArgumentException("Invalid locale format: " + str);
    }

    if (len == 1) {
        return new Locale(language);
    }

    String country = parts[1];
    if (len == 2) {
        if (country.isEmpty()) {
            throw new IllegalArgumentException("Invalid locale format: " + str);
        }
        if (country.length() == 2 && isAllUpperCaseAlpha(country)) {
            return new Locale(language, country);
        } else {
            // Variant only (no country)
            return new Locale(language, "", country);
        }
    }

    // len == 3
    if (!country.isEmpty() && (country.length() != 2 || !isAllUpperCaseAlpha(country))) {
        throw new IllegalArgumentException("Invalid locale format: " + str);
    }
    String variant = parts[2];
    return new Locale(language, country, variant);
}

