    /**
     * Security fix: Check if the type is allowed for deserialization
     * Blocks known dangerous types that could lead to remote code execution
     */
    protected void _checkIfValidType(DeserializationContext ctxt, JavaType type) 
        throws JsonMappingException 
    {
        Class<?> rawClass = type.getRawClass();
        String className = rawClass.getName();

        // Block known dangerous types
        if (_isBlockedClass(rawClass)) {
            String msg = String.format("Blocked deserialization of type %s for security reasons", 
                className);
            throw ctxt.mappingException(msg);
        }
    }

    /**
     * Security fix: Check if a class is in the blocked list
     */
    protected boolean _isBlockedClass(Class<?> clazz) {
        String className = clazz.getName();

        // Block java.lang.Class and related types that could enable code execution
        if (className.startsWith("java.lang.Class") ||
            className.startsWith("javax.management.") ||
            className.startsWith("java.rmi.") ||
            className.startsWith("org.springframework.") ||
            className.startsWith("org.apache.commons.collections.") ||
            className.startsWith("com.sun.") ||
            className.equals("java.lang.ProcessBuilder") ||
            className.equals("java.lang.Runtime") ||
            className.equals("java.lang.System") ||
            className.equals("java.lang.Thread") ||
            className.equals("java.sql.DriverManager") ||
            className.equals("java.util.logging.") ||
            className.equals("org.slf4j.") ||
            className.equals("ch.qos.logback.")) {
            return true;
        }

        // Additional checks for arrays of blocked types
        if (clazz.isArray()) {
            return _isBlockedClass(clazz.getComponentType());
        }

        return false;
    }

@Override
    public JsonDeserializer<Object> createBeanDeserializer(DeserializationContext ctxt,
            JavaType type, BeanDescription beanDesc)
        throws JsonMappingException
    {
        final DeserializationConfig config = ctxt.getConfig();

        // Security fix: Check for potentially dangerous types before proceeding
        Class<?> rawClass = type.getRawClass();
        if (_isDangerousType(rawClass)) {
            return null;
        }

        // We may also have custom overrides:
        JsonDeserializer<Object> custom = _findCustomBeanDeserializer(type, config, beanDesc);
        if (custom != null) {
            return custom;
        }
        /* One more thing to check: do we have an exception type
         * (Throwable or its sub-classes)? If so, need slightly
         * different handling.
         */
        if (type.isThrowable()) {
            return buildThrowableDeserializer(ctxt, type, beanDesc);
        }
        /* Or, for abstract types, may have alternate means for resolution
         * (defaulting, materialization)
         */
        // 29-Nov-2015, tatu: Also, filter out calls to primitive types, they are
        //    not something we could materialize anything for
        if (type.isAbstract() && !type.isPrimitive() && !type.isEnumType()) {
            // Let's make it possible to materialize abstract types.
            JavaType concreteType = materializeAbstractType(ctxt, type, beanDesc);
            if (concreteType != null) {
                // Security fix: Check the concrete type as well
                if (_isDangerousType(concreteType.getRawClass())) {
                    return null;
                }
                /* important: introspect actual implementation (abstract class or
                 * interface doesn't have constructors, for one)
                 */
                beanDesc = config.introspect(concreteType);
                return buildBeanDeserializer(ctxt, concreteType, beanDesc);
            }
        }
        // Otherwise, may want to check handlers for standard types, from superclass:
        @SuppressWarnings("unchecked")
        JsonDeserializer<Object> deser = (JsonDeserializer<Object>) findStdDeserializer(ctxt, type, beanDesc);
        if (deser != null) {
            return deser;
        }

        // Otherwise: could the class be a Bean class? If not, bail out
        if (!isPotentialBeanType(type.getRawClass())) {
            return null;
        }
        // For checks like [databind#1599]
        // Use generic bean introspection to build deserializer
        return buildBeanDeserializer(ctxt, type, beanDesc);
    }

    // Security fix: Add method to check for dangerous types
    protected boolean _isDangerousType(Class<?> clazz) {
        // Block known dangerous types that could be exploited
        String className = clazz.getName();

        // Block types that could lead to remote code execution
        if (className.startsWith("java.util.") && 
            (className.contains("PriorityQueue") || className.contains("ArrayDeque"))) {
            return true;
        }

        // Block scripting and reflection related classes
        if (className.startsWith("com.sun.") || 
            className.startsWith("java.lang.invoke.") ||
            className.startsWith("sun.reflect.") ||
            className.startsWith("javax.script.") ||
            className.startsWith("org.springframework.") ||
            className.startsWith("org.apache.commons.beanutils.") ||
            className.startsWith("org.apache.xalan.") ||
            className.startsWith("org.codehaus.groovy.") ||
            className.startsWith("com.thoughtworks.xstream.")) {
            return true;
        }

        // Block types that could be used for gadget chains
        if (className.equals("java.lang.ProcessBuilder") ||
            className.equals("java.lang.Runtime") ||
            className.equals("java.lang.System") ||
            className.equals("java.lang.Class") ||
            className.equals("java.lang.reflect.Constructor") ||
            className.equals("java.lang.reflect.Method") ||
            className.equals("java.lang.reflect.Field") ||
            className.equals("java.util.ServiceLoader") ||
            className.equals("java.net.URL") ||
            className.equals("java.net.URLClassLoader") ||
            className.equals("javax.xml.transform.Templates")) {
            return true;
        }

        return false;
    }

