protected RealPointValuePair getSolution() {
    double[] coefficients = new double[getOriginalNumDecisionVariables()];
    Integer basicRow =
        getBasicRow(getNumObjectiveFunctions() + getOriginalNumDecisionVariables());
    double mostNegative = basicRow == null ? 0 : getEntry(basicRow, getRhsOffset());
    for (int i = 0; i < coefficients.length; i++) {
        basicRow = getBasicRow(getNumObjectiveFunctions() + i);
        if (basicRow != null) {
            coefficients[i] = getEntry(basicRow, getRhsOffset());
            // Check if this is truly a basic variable by verifying 
            // there's exactly one '1' in its column in basic rows
            boolean isBasic = true;
            for (int j = 0; j < getHeight(); j++) {
                if (j != basicRow && Math.abs(getEntry(j, getNumObjectiveFunctions() + i)) > 1.0e-6) {
                    isBasic = false;
                    break;
                }
            }
            if (!isBasic) {
                coefficients[i] = 0;
            }
        } else {
            coefficients[i] = 0;
        }

        if (!restrictToNonNegative) {
            coefficients[i] = coefficients[i] - mostNegative;
        }
    }
    return new RealPointValuePair(coefficients, f.getValue(coefficients));
}

protected RealPointValuePair getSolution() {
    double[] coefficients = new double[getOriginalNumDecisionVariables()];
    Integer basicRow =
        getBasicRow(getNumObjectiveFunctions() + getOriginalNumDecisionVariables());
    double mostNegative = basicRow == null ? 0 : getEntry(basicRow, getRhsOffset());
    for (int i = 0; i < coefficients.length; i++) {
        basicRow = getBasicRow(getNumObjectiveFunctions() + i);
        if (basicRow != null) {
            coefficients[i] = getEntry(basicRow, getRhsOffset());
            // Check if this is actually a basic variable
            boolean isBasic = true;
            for (int j = getNumObjectiveFunctions(); j < getNumObjectiveFunctions() + getOriginalNumDecisionVariables(); j++) {
                if (j != getNumObjectiveFunctions() + i && Math.abs(getEntry(basicRow, j)) > 1.0e-6) {
                    isBasic = false;
                    break;
                }
            }
            if (!isBasic) {
                coefficients[i] = 0;
            }
        } else {
            coefficients[i] = 0;
        }

        if (!restrictToNonNegative && coefficients[i] < mostNegative) {
            coefficients[i] -= mostNegative;
        }
    }
    return new RealPointValuePair(coefficients, f.getValue(coefficients));
}
